android.extraProguardRules:
# ─── React Native + Hermes ─────────────────────────────────────────
-keep class com.facebook.react.** { *; }
-keep class com.facebook.hermes.** { *; }
-keep class com.facebook.jni.** { *; }
-dontwarn com.facebook.react.**
-dontwarn com.facebook.hermes.**

# ─── Reanimated + Worklets (Pass 6 dropped moti, kept reanimated) ──
-keep class com.swmansion.reanimated.** { *; }
-keep class com.swmansion.worklets.** { *; }
-dontwarn com.swmansion.**

# ─── MMKV + Nitro Modules (Pass 5b storage layer) ─────────────────
-keep class com.mrousavy.mmkv.** { *; }
-keep class com.margelo.nitro.** { *; }
-dontwarn com.mrousavy.**
-dontwarn com.margelo.**

# ─── Expo modules (autolinked, reflection-driven) ─────────────────
-keep class expo.modules.** { *; }
-keep class versioned.host.exp.exponent.** { *; }
-dontwarn expo.modules.**

# ─── Native SQLite bindings (expo-sqlite uses JNI) ────────────────
-keep class io.expo.sqlite.** { *; }

# ─── Anthropic SDK / OCR client (lib/api.ts) ──────────────────────
# Pure JS, no Java keep rules needed.

# ─── Drop debug-only logging from release ─────────────────────────
-assumenosideeffects class android.util.Log {
    public static *** v(...);
    public static *** d(...);
}
